{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 4f);
var crystalSize = GetFloat(parameters, "crystalSize", 0.5f);
var crystalSharpness = GetFloat(parameters, "crystalSharpness", 0.6f);
var frostAmount = GetFloat(parameters, "frostAmount", 0.4f);
var crackDensity = GetFloat(parameters, "crackDensity", 0.3f);
var iceColor = GetColor(parameters, "iceColor", Color.FromRgb(180, 220, 255));
var deepIceColor = GetColor(parameters, "deepIceColor", Color.FromRgb(100, 160, 220));
var frostColor = GetColor(parameters, "frostColor", Color.FromRgb(220, 235, 250));
var glossiness = GetFloat(parameters, "glossiness", 0.5f);
var opacity = GetFloat(parameters, "opacity", 0.7f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var iR = iceColor.R / 255f; var iG = iceColor.G / 255f; var iB = iceColor.B / 255f;
var dR = deepIceColor.R / 255f; var dG = deepIceColor.G / 255f; var dB = deepIceColor.B / 255f;
var fR = frostColor.R / 255f; var fG = frostColor.G / 255f; var fB = frostColor.B / 255f;

// Generate Voronoi points for crystal facets
var cellCount = (int)(scale * crystalSize * 4);
cellCount = Math.Max(4, Math.Min(cellCount, 50));
var crystals = new (float x, float y, float hash, float angle)[cellCount];
for (var i = 0; i < cellCount; i++)
{
    crystals[i] = (
        HashToUnit(i * 7, seed, 111),
        HashToUnit(i * 13, seed * 3, 222),
        HashToUnit(i * 17, seed * 5, 333),
        HashToUnit(i * 23, seed * 7, 444) * MathF.PI * 2f
    );
}

var period = Math.Max(1, (int)MathF.Round(scale * 6f));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // --- Crystal structure (Voronoi) ---
    var minDist = float.MaxValue;
    var minDist2 = float.MaxValue;
    var nearHash = 0f;
    var nearAngle = 0f;
    var nearCX = 0f;
    var nearCY = 0f;

    foreach (var (cx, cy, ch, ca) in crystals)
    {
        var dx = u - cx;
        var dy = v - cy;
        if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
        if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;

        var dist = dx * dx + dy * dy;
        if (dist < minDist)
        {
            minDist2 = minDist;
            minDist = dist;
            nearHash = ch;
            nearAngle = ca;
            nearCX = dx;
            nearCY = dy;
        }
        else if (dist < minDist2)
        {
            minDist2 = dist;
        }
    }

    var cellDist = MathF.Sqrt(minDist);
    var edgeDist = MathF.Sqrt(minDist2) - cellDist;

    // Crystal facet effect: sharp color transition at cell boundaries
    var crystalEdge = MathF.Max(0f, 1f - edgeDist * scale * 6f);

    // Facet angle-based shading (iridescent effect)
    var facetShade = 0.5f + MathF.Cos(nearAngle + nearCX * 3f + nearCY * 2f) * 0.3f;

    // --- Ice base color ---
    // Deep ice where crystals are thick, lighter at edges
    var crystalDepth = 1f - cellDist * scale * 1.5f;
    crystalDepth = Math.Clamp(crystalDepth, 0f, 1f);

    var iceR = Lerp(dR, iR, crystalDepth);
    var iceG = Lerp(dG, iG, crystalDepth);
    var iceB = Lerp(dB, iB, crystalDepth);

    // Facet shading
    iceR *= facetShade;
    iceG *= facetShade;
    iceB *= facetShade;

    // Crystal edge glow (light refraction at boundaries)
    var edgeGlow = crystalEdge * 0.3f;
    iceR = Math.Clamp(iceR + edgeGlow, 0f, 1f);
    iceG = Math.Clamp(iceG + edgeGlow * 0.9f, 0f, 1f);
    iceB = Math.Clamp(iceB + edgeGlow * 1.3f, 0f, 1f);

    // --- Frost accumulation ---
    var frost = 0f;
    if (frostAmount > 0f)
    {
        // Frost forms on crystal edges and in clusters
        var frostNoise = TileableFractalNoise(
            u * scale * 2f, v * scale * 2f,
            period, 3, 0.5f, 2.2f, seed + 100);

        var frostEdge = crystalEdge * frostAmount * 0.5f;
        frost = frostNoise * frostAmount * 0.6f + frostEdge;
        frost = Math.Clamp(frost, 0f, 1f);

        // Frost detail
        var frostDetail = TileableFractalNoise(
            u * scale * 6f, v * scale * 6f,
            Math.Max(1, period / 2), 2, 0.5f, 2.5f, seed + 200);
        frost *= frostDetail > 0.3f ? 1f : frostDetail * 3f;
        frost = Math.Clamp(frost, 0f, 1f);
    }

    // --- Cracks ---
    var crack = 0f;
    if (crackDensity > 0f)
    {
        // Cracks follow cell boundaries (edge detection)
        var crackNoise = TileableFractalNoise(
            u * scale * 1.5f + 50f, v * scale * 1.5f + 50f,
            period, 2, 0.5f, 2f, seed + 300);

        var crackSignal = crystalEdge * crackDensity * crackNoise;
        if (crackSignal > 0.4f)
        {
            crack = (crackSignal - 0.4f) / 0.6f;
            crack = Math.Clamp(crack, 0f, 1f);
        }
    }

    // --- Gloss / specular highlight ---
    var spec = 0f;
    if (glossiness > 0f)
    {
        var specNoise = TileableFractalNoise(
            u * scale * 3f, v * scale * 3f,
            Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 400);
        spec = MathF.Pow(specNoise, 4f) * glossiness * 0.5f;
    }

    // --- Compose layers ---
    float r, g, b;

    // Apply frost
    r = Lerp(iceR, fR, frost);
    g = Lerp(iceG, fG, frost);
    b = Lerp(iceB, fB, frost);

    // Apply cracks (dark lines)
    if (crack > 0f)
    {
        var crackDark = crack * 0.5f;
        r = Math.Clamp(r - crackDark, 0f, 1f);
        g = Math.Clamp(g - crackDark * 0.9f, 0f, 1f);
        b = Math.Clamp(b - crackDark * 0.8f, 0f, 1f);
    }

    // Add specular highlights
    r = Math.Clamp(r + spec, 0f, 1f);
    g = Math.Clamp(g + spec * 0.9f, 0f, 1f);
    b = Math.Clamp(b + spec * 1.1f, 0f, 1f);

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), opacity);
});

return buffer;
}
